  1→import { describe, expect, it } from "bun:test";
  2→import { RecordId } from "surrealdb";
  3→import { createTestUser, fetchJson, setupSmokeSuite } from "../smoke-test-kit";
  4→
  5→/**
  6→ * US-5: GitHub commit processor sets task status to done on push to non-main branch.
  7→ * US-6: GitHub commit processor sets task status to completed on merge to main.
  8→ *
  9→ * These tests extend the existing github-webhook smoke test to validate
 10→ * that push events trigger task status transitions based on branch.
 11→ */
 12→
 13→const getRuntime = setupSmokeSuite("webhook-status");
 14→
 15→function makePushEvent(overrides: {
 16→  ref?: string;
 17→  defaultBranch?: string;
 18→  commits?: Array<{
 19→    id: string;
 20→    message: string;
 21→    timestamp: string;
 22→    url: string;
 23→    author: { name: string; email: string; username?: string };
 24→  }>;
 25→}) {
 26→  const defaultBranch = overrides.defaultBranch ?? "main";
 27→  return {
 28→    ref: overrides.ref ?? `refs/heads/${defaultBranch}`,
 29→    repository: {
 30→      full_name: "acme/brain",
 31→      default_branch: defaultBranch,
 32→      html_url: "https://github.com/acme/brain",
 33→    },
 34→    commits: overrides.commits ?? [],
 35→  };
 36→}
 37→
 38→async function pollForTaskStatus(
 39→  surreal: ReturnType<typeof setupSmokeSuite> extends () => infer R ? (R extends { surreal: infer S } ? S : never) : never,
 40→  taskRecord: RecordId<"task", string>,
 41→  expectedStatus: string,
 42→  timeoutMs: number,
 43→): Promise<string | undefined> {
 44→  const start = Date.now();
 45→  while (Date.now() - start < timeoutMs) {
 46→    const [rows] = await surreal
 47→      .query<[Array<{ status: string }>]>(
 48→        "SELECT status FROM $task;",
 49→        { task: taskRecord },
 50→      )
 51→      .collect<[Array<{ status: string }>]>();
 52→    if (rows[0]?.status === expectedStatus) return rows[0].status;
 53→    await Bun.sleep(500);
 54→  }
 55→  // Return whatever status it has now
 56→  const [rows] = await surreal
 57→    .query<[Array<{ status: string }>]>(
 58→      "SELECT status FROM $task;",
 59→      { task: taskRecord },
 60→    )
 61→    .collect<[Array<{ status: string }>]>();
 62→  return rows[0]?.status;
 63→}
 64→
 65→async function setupWorkspaceWithTask(
 66→  baseUrl: string,
 67→  surreal: ReturnType<typeof setupSmokeSuite> extends () => infer R ? (R extends { surreal: infer S } ? S : never) : never,
 68→  suffix: string,
 69→  taskStatus: string,
 70→) {
 71→  const user = await createTestUser(baseUrl, `wh-status-${suffix}`);
 72→
 73→  const workspace = await fetchJson<{ workspaceId: string }>(
 74→    `${baseUrl}/api/workspaces`,
 75→    {
 76→      method: "POST",
 77→      headers: { "Content-Type": "application/json", ...user.headers },
 78→      body: JSON.stringify({ name: `Webhook Status ${Date.now()} ${suffix}` }),
 79→    },
 80→  );
 81→
 82→  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
 83→  const taskId = `wh-task-${suffix}-${Date.now()}`;
 84→  const taskRecord = new RecordId("task", taskId);
 85→
 86→  await surreal.create(taskRecord).content({
 87→    workspace: workspaceRecord,
 88→    title: `Webhook status test task ${suffix}`,
 89→    status: taskStatus,
 90→    category: "backend",
 91→    priority: "medium",
 92→    created_at: new Date(),
 93→    updated_at: new Date(),
 94→  });
 95→
 96→  return { user, workspace, workspaceRecord, taskId, taskRecord };
 97→}
 98→
 99→describe("GitHub push to feature branch sets task to done (US-5)", () => {
100→  // Walking skeleton: push to feature branch with task ref -> task done
101→
102→  it.skip("Given a task in_progress, When a commit referencing it is pushed to a feature branch, Then the task status becomes 'done' and an implemented_by relation is created", async () => {
103→    const { baseUrl, surreal } = getRuntime();
104→    const { workspace, taskId, taskRecord } = await setupWorkspaceWithTask(
105→      baseUrl, surreal, "feat-done-1", "in_progress",
106→    );
107→
108→    const sha = `feat${Date.now().toString(16)}deadbeef`;
109→    const event = makePushEvent({
110→      ref: "refs/heads/feature/login",
111→      defaultBranch: "main",
112→      commits: [{
113→        id: sha,
114→        message: `task:${taskId} implement login flow`,
115→        timestamp: new Date().toISOString(),
116→        url: `https://github.com/acme/brain/commit/${sha}`,
117→        author: { name: "Marcus", email: "marcus@test.com", username: "marcus-sa" },
118→      }],
119→    });
120→
121→    const res = await fetch(
122→      `${baseUrl}/api/workspaces/${workspace.workspaceId}/webhooks/github`,
123→      {
124→        method: "POST",
125→        headers: {
126→          "Content-Type": "application/json",
127→          "x-github-event": "push",
128→        },
129→        body: JSON.stringify(event),
130→      },
131→    );
132→
133→    expect(res.status).toBe(202);
134→
135→    // Poll for task status to change to done (async processing)
136→    const finalStatus = await pollForTaskStatus(surreal, taskRecord, "done", 20_000);
137→    expect(finalStatus).toBe("done");
138→
139→    // Verify implemented_by relation exists
140→    const [linkRows] = await surreal
141→      .query<[Array<{ id: RecordId }>]>(
142→        "SELECT id FROM implemented_by WHERE `in` = $task;",
143→        { task: taskRecord },
144→      )
145→      .collect<[Array<{ id: RecordId }>]>();
146→
147→    expect(linkRows.length).toBeGreaterThan(0);
148→  }, 45_000);
149→
150→  it.skip("Given a task already 'done', When a push references it on a feature branch, Then the task remains 'done' (idempotent)", async () => {
151→    const { baseUrl, surreal } = getRuntime();
152→    const { workspace, taskId, taskRecord } = await setupWorkspaceWithTask(
153→      baseUrl, surreal, "feat-idemp-1", "done",
154→    );
155→
156→    const sha = `idemp${Date.now().toString(16)}deadbeef`;
157→    const event = makePushEvent({
158→      ref: "refs/heads/feature/cleanup",
159→      defaultBranch: "main",
160→      commits: [{
161→        id: sha,
162→        message: `task:${taskId} minor cleanup`,
163→        timestamp: new Date().toISOString(),
164→        url: `https://github.com/acme/brain/commit/${sha}`,
165→        author: { name: "Marcus", email: "marcus@test.com" },
166→      }],
167→    });
168→
169→    await fetch(
170→      `${baseUrl}/api/workspaces/${workspace.workspaceId}/webhooks/github`,
171→      {
172→        method: "POST",
173→        headers: {
174→          "Content-Type": "application/json",
175→          "x-github-event": "push",
176→        },
177→        body: JSON.stringify(event),
178→      },
179→    );
180→
181→    // Wait a bit for async processing
182→    await Bun.sleep(5_000);
183→
184→    const [rows] = await surreal
185→      .query<[Array<{ status: string }>]>(
186→        "SELECT status FROM $task;",
187→        { task: taskRecord },
188→      )
189→      .collect<[Array<{ status: string }>]>();
190→
191→    expect(rows[0]?.status).toBe("done");
192→  }, 30_000);
193→});
194→
195→describe("GitHub push to main sets task to completed (US-6)", () => {
196→  // Walking skeleton: merge to main -> task completed
197→
198→  it.skip("Given a task with status 'done', When a commit referencing it is pushed to main, Then the task status becomes 'completed'", async () => {
199→    const { baseUrl, surreal } = getRuntime();
200→    const { workspace, taskId, taskRecord } = await setupWorkspaceWithTask(
201→      baseUrl, surreal, "main-comp-1", "done",
202→    );
203→
204→    const sha = `main${Date.now().toString(16)}deadbeef`;
205→    const event = makePushEvent({
206→      ref: "refs/heads/main",
207→      defaultBranch: "main",
208→      commits: [{
209→        id: sha,
