212→        url: `https://github.com/acme/brain/commit/${sha}`,
213→        author: { name: "Marcus", email: "marcus@test.com", username: "marcus-sa" },
214→      }],
215→    });
216→
217→    const res = await fetch(
218→      `${baseUrl}/api/workspaces/${workspace.workspaceId}/webhooks/github`,
219→      {
220→        method: "POST",
221→        headers: {
222→          "Content-Type": "application/json",
223→          "x-github-event": "push",
224→        },
225→        body: JSON.stringify(event),
226→      },
227→    );
228→
229→    expect(res.status).toBe(202);
230→
231→    const finalStatus = await pollForTaskStatus(surreal, taskRecord, "completed", 20_000);
232→    expect(finalStatus).toBe("completed");
233→  }, 45_000);
234→
235→  it.skip("Given a task with status 'in_progress', When a commit referencing it lands on main, Then the task status becomes 'completed'", async () => {
236→    const { baseUrl, surreal } = getRuntime();
237→    const { workspace, taskId, taskRecord } = await setupWorkspaceWithTask(
238→      baseUrl, surreal, "main-skip-1", "in_progress",
239→    );
240→
241→    const sha = `skip${Date.now().toString(16)}deadbeef`;
242→    const event = makePushEvent({
243→      ref: "refs/heads/main",
244→      defaultBranch: "main",
245→      commits: [{
246→        id: sha,
247→        message: `task:${taskId} direct commit to main`,
248→        timestamp: new Date().toISOString(),
249→        url: `https://github.com/acme/brain/commit/${sha}`,
250→        author: { name: "Marcus", email: "marcus@test.com" },
251→      }],
