267→    expect(finalStatus).toBe("completed");
268→  }, 45_000);
269→
270→  it.skip("Given a task already 'completed', When a merge to main references it again, Then the task remains 'completed' (idempotent)", async () => {
271→    const { baseUrl, surreal } = getRuntime();
