  2→import { readFileSync } from "node:fs";
  3→import { join } from "node:path";
  4→import { Surreal } from "surrealdb";
  5→import { createBrainServer } from "../../app/src/server/runtime/start-server";
  6→import { createRuntimeDependencies } from "../../app/src/server/runtime/dependencies";
  7→import { createSseRegistry } from "../../app/src/server/streaming/sse-registry";
  8→import type { ServerConfig } from "../../app/src/server/runtime/config";
  9→import type { ServerDependencies } from "../../app/src/server/runtime/types";
 10→
 11→export type SmokeTestRuntime = {
 12→  baseUrl: string;
 13→  surreal: Surreal;
 14→  namespace: string;
 15→  database: string;
 16→  port: number;
 17→};
 18→
 19→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 20→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 21→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 22→
 23→export function setupSmokeSuite(suiteName: string): () => SmokeTestRuntime {
 24→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 25→  const namespace = `smoke_${runId}`;
 26→  const suiteSlug = suiteName
 27→    .toLowerCase()
 28→    .replace(/[^a-z0-9]+/g, "_")
 29→    .replace(/^_+|_+$/g, "");
 30→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
 31→
 32→  let runtime: SmokeTestRuntime | undefined;
 33→  let server: ReturnType<typeof Bun.serve> | undefined;
 34→  let runtimeSurreal: Surreal | undefined;
 35→  let analyticsSurreal: Surreal | undefined;
 36→  let setupSucceeded = false;
 37→
 38→  beforeAll(async () => {
 39→    const surreal = new Surreal();
 40→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
 41→    await withTimeout(
 42→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
 43→      10_000,
 44→      "authenticate with SurrealDB",
 45→    );
 46→
 47→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
 48→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
 49→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
 50→    await withTimeout(
 51→      () => surreal.use({ namespace, database }),
 52→      10_000,
 53→      "switch to test namespace/database",
 54→    );
 55→
 56→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 57→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
 58→
 59→    const config: ServerConfig = {
 60→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
 61→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
 62→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
 63→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
 64→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
 65→      embeddingModelId: requireTestEnv("OPENROUTER_EMBEDDING_MODEL"),
 66→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
 67→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
 68→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
 69→      surrealUrl,
 70→      surrealUsername,
 71→      surrealPassword,
 72→      surrealNamespace: namespace,
 73→      surrealDatabase: database,
 74→      port: 0, // OS-assigned
 75→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
 76→      betterAuthUrl: "http://127.0.0.1:0", // placeholder, updated after server starts
 77→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
 78→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
 79→    };
 80→
 81→    const deps = await createRuntimeDependencies(config);
 82→    runtimeSurreal = deps.surreal;
 83→    analyticsSurreal = deps.analyticsSurreal;
 84→
 85→    const serverDeps: ServerDependencies = {
 86→      config,
 87→      surreal: deps.surreal,
 88→      analyticsSurreal: deps.analyticsSurreal,
 89→      auth: deps.auth,
 90→      chatAgentModel: deps.chatAgentModel,
 91→      extractionModel: deps.extractionModel,
 92→      pmAgentModel: deps.pmAgentModel,
 93→      analyticsAgentModel: deps.analyticsAgentModel,
 94→      embeddingModel: deps.embeddingModel,
 95→      sse: createSseRegistry(),
 96→    };
 97→
 98→    server = createBrainServer(serverDeps);
 99→    const port = server.port;
100→    const baseUrl = `http://127.0.0.1:${port}`;
101→    // Update betterAuthUrl now that we know the actual port
102→    config.betterAuthUrl = baseUrl;
103→
104→    runtime = { baseUrl, surreal, namespace, database, port };
105→    setupSucceeded = true;
106→  }, 60_000);
107→
108→  afterAll(async () => {
109→    if (server) {
110→      server.stop(true);
111→    }
112→
113→    if (runtimeSurreal) {
114→      await runtimeSurreal.close().catch(() => undefined);
115→    }
116→    if (analyticsSurreal) {
117→      await analyticsSurreal.close().catch(() => undefined);
118→    }
119→
120→    if (!runtime) {
121→      return;
122→    }
123→
124→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
125→      try {
126→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
127→      } catch {
128→        // Best effort cleanup.
129→      }
130→
131→      try {
132→        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
133→      } catch {
134→        // Best effort cleanup.
135→      }
136→    }
137→
138→    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
139→  }, 20_000);
140→
141→  return () => {
142→    if (!runtime) {
143→      throw new Error("Smoke runtime requested before suite setup completed");
144→    }
145→    return runtime;
146→  };
147→}
