153→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
154→  const email = `smoke-${Date.now()}-${suffix}@test.local`;
155→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
156→    method: "POST",
157→    headers: { "Content-Type": "application/json" },
158→    body: JSON.stringify({ name: "Smoke Tester", email, password: "smoke-test-password-123" }),
159→    redirect: "manual",
160→  });
161→
162→  if (!response.ok) {
163→    const body = await response.text();
164→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
165→  }
166→
167→  const setCookie = response.headers.getSetCookie();
168→  if (!setCookie || setCookie.length === 0) {
169→    throw new Error("Sign-up did not return session cookies");
170→  }
171→
172→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
173→  return { headers: { Cookie: cookieHeader } };
174→}
