176→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
177→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
178→  if (!response.ok || !response.body) {
179→    throw new Error(`Failed to open SSE stream (${response.status})`);
180→  }
181→
182→  const reader = response.body.getReader();
183→  const decoder = new TextDecoder();
184→  const events: T[] = [];
185→  let buffer = "";
186→
187→  const timeout = setTimeout(() => {
188→    void reader.cancel();
189→  }, timeoutMs);
190→
191→  try {
192→    while (true) {
193→      const { value, done } = await reader.read();
194→      if (done) {
195→        break;
