  1→import { describe, expect, it } from "bun:test";
  2→import { RecordId } from "surrealdb";
  3→import { createTestUserWithMcp, fetchJson, setupSmokeSuite } from "../smoke-test-kit";
  4→
  5→/**
  6→ * Backward transitions (unchanged behavior).
  7→ * Server owns abort and reject -- these reset task status to ready.
  8→ *
  9→ * These tests verify that backward transitions continue to work correctly
 10→ * after forward transitions are moved to agents/processors.
 11→ */
 12→
 13→const getRuntime = setupSmokeSuite("backward-transitions");
 14→
 15→async function createSessionWithTask(
 16→  baseUrl: string,
 17→  surreal: ReturnType<typeof setupSmokeSuite> extends () => infer R ? (R extends { surreal: infer S } ? S : never) : never,
 18→  suffix: string,
 19→  taskStatus: string,
 20→) {
 21→  const user = await createTestUserWithMcp(baseUrl, surreal, `backward-${suffix}`, "session:write graph:read offline_access");
 22→
 23→  const workspace = await fetchJson<{ workspaceId: string }>(
 24→    `${baseUrl}/api/workspaces`,
 25→    {
 26→      method: "POST",
 27→      headers: { "Content-Type": "application/json", ...user.headers },
 28→      body: JSON.stringify({ name: `Backward ${Date.now()} ${suffix}` }),
 29→    },
 30→  );
 31→
 32→  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
 33→  const taskId = `backward-task-${suffix}-${Date.now()}`;
 34→  const taskRecord = new RecordId("task", taskId);
 35→
 36→  await surreal.create(taskRecord).content({
 37→    workspace: workspaceRecord,
 38→    title: `Backward transition test ${suffix}`,
 39→    status: taskStatus,
 40→    category: "engineering",
 41→    priority: "medium",
 42→    created_at: new Date(),
 43→    updated_at: new Date(),
 44→  });
