151→/** Helper: POST to an MCP endpoint with Bearer token */
152→function mcpPost(baseUrl: string, workspaceId: string, path: string, token: string, body: unknown = {}) {
153→  return fetch(`${baseUrl}/api/mcp/${workspaceId}${path}`, {
154→    method: "POST",
155→    headers: {
156→      "Content-Type": "application/json",
157→      Authorization: `Bearer ${token}`,
158→    },
159→    body: JSON.stringify(body),
160→  });
161→}
162→
163→/** Helper: GET an MCP endpoint with Bearer token */
164→function mcpGet(baseUrl: string, workspaceId: string, path: string, token: string) {
165→  return fetch(`${baseUrl}/api/mcp/${workspaceId}${path}`, {
166→    headers: {
167→      "Content-Type": "application/json",
168→      Authorization: `Bearer ${token}`,
169→    },
170→  });
171→}
