173→describe("OAuth MCP Auth", () => {
174→  const ALL_SCOPES = "graph:read graph:reason decision:write task:write observation:write question:write session:write offline_access";
175→  let workspaceId: string;
176→  let fullToken: string;
177→
178→  it("setup: create workspace and person with OAuth tokens", async () => {
179→    const { baseUrl, surreal } = getRuntime();
180→
181→    // Create workspace with all required SCHEMAFULL fields
182→    workspaceId = crypto.randomUUID();
183→    const wsRecord = new RecordId("workspace", workspaceId);
184→    await surreal.query(
185→      `CREATE $ws CONTENT {
186→        name: "OAuth Test Workspace",
187→        status: "active",
188→        onboarding_complete: true,
189→        onboarding_turn_count: 0,
190→        onboarding_summary_pending: false,
191→        onboarding_started_at: time::now(),
192→        created_at: time::now()
193→      };`,
194→      { ws: wsRecord },
195→    );
196→
197→    // Create project linked to workspace
198→    const projRecord = new RecordId("project", crypto.randomUUID());
199→    await surreal.query(
200→      `CREATE $proj CONTENT {
201→        name: "Test Project",
202→        status: "active",
203→        workspace: $ws,
204→        created_at: time::now()
205→      };`,
206→      { proj: projRecord, ws: wsRecord },
207→    );
208→    await surreal.query(
209→      `RELATE $ws->has_project->$proj SET added_at = time::now();`,
210→      { ws: wsRecord, proj: projRecord },
211→    );
212→
213→    // Sign up a user
214→    const { userId } = await signUpAndGetSession(baseUrl, "oauth-test@example.com", "OAuth Tester");
215→
216→    // Create identity + spoke edge, then member_of (identity -> workspace)
217→    const personRecord = new RecordId("person", userId);
218→    const identityRecord = new RecordId("identity", crypto.randomUUID());
219→    await surreal.query(
220→      `CREATE $identity CONTENT { name: "OAuth Tester", type: "human", role: "admin", workspace: $ws, created_at: time::now() };`,
221→      { identity: identityRecord, ws: wsRecord },
222→    );
223→    await surreal.query(
224→      `RELATE $identity->identity_person->$person SET added_at = time::now();`,
225→      { identity: identityRecord, person: personRecord },
226→    );
227→    await surreal.query(
228→      `RELATE $identity->member_of->$ws SET role = "admin", added_at = time::now();`,
229→      { identity: identityRecord, ws: wsRecord },
230→    );
231→
232→    // Trigger JWKS key generation by hitting the JWKS endpoint
233→    await fetch(`${baseUrl}/api/auth/jwks`);
234→
235→    // Get OAuth tokens with all scopes
236→    const session = await signInAndGetSession(baseUrl, "oauth-test@example.com");
237→    const tokens = await getOAuthTokens(baseUrl, surreal, session.headers, ALL_SCOPES);
238→    fullToken = tokens.accessToken;
239→
240→    expect(fullToken).toBeTruthy();
241→  }, 30_000);
